//! The jump-GCD schedule data that drives the reversible secp256k1 EC point-add
//! circuit. These baked tables deterministically replace any live cost-model
//! decision, so the emitted circuit is fixed per call.
//!
//! `SCHED_J2`/`GAP_J2` (len 258) are the jump-GCD register-width and
//! comparator-window schedules, read by the GCD circuit builder in `gcd.rs`;
//! `PAD` is the +f reduction carry-cap. The remaining tables are loaded by
//! `mod.rs`'s `load_schedule` and consumed in sequence via its `next_*` functions.

/// Jump value the GCD path uses. The packed/pairs codecs and the entire apply
/// phase are jump=2-specific.
pub const JUMP: usize = 2;

/// iters budget == `SCHED_J2.len()`. The GCD must reach `gcd=1` within this many
/// jump-GCD steps or the schedule reports non-convergence.
pub const ITERS: usize = 258;

/// `+f` pseudo-Mersenne / chunked-carry padding. A +f reduction carry that runs
/// past the low `PAD + bitlen(f)` bits is dropped; per fire that happens with
/// probability ~2^-PAD over a uniform mod-q operand.
pub const PAD: usize = 21;



/// Per-step register width for jump=2. At GCD step `i` the circuit holds only
/// `SCHED_J2[i]` bits of the GCD state; a step whose
/// `max(bitlen(u), bitlen(v)) > SCHED_J2[i]` truncates a needed bit.
